//用于合并更新单行or勾选行数据与未更新的数据行

import { ref, watch, computed } from 'vue'
export function useDataMerge(
  dataGetter,
  options = {
    idField: 'devid'
  }
) {
  const lastData = ref([])

  watch(dataGetter, (newData) => {
    if (newData) {
      // 只有在收到完整数据时才更新 lastData
      // 通过 options.idField 判断是否包含了所有可能的 ID
      const currentIds = new Set(newData.map((item) => item[options.idField]))
      const lastIds = new Set(
        lastData.value.map((item) => item[options.idField])
      )

      // 如果当前数据包含了新的 ID，或者是首次加载，就更新 lastData
      if (currentIds.size > lastIds.size || lastData.value.length === 0) {
        lastData.value = newData
      }
    }
  })

  const mergedData = computed(() => {
    const currentData = dataGetter.value
    if (!currentData) return []

    // 只要当前数据不是完整数据，就进行合并
    if (
      currentData.length !== lastData.value.length &&
      lastData.value.length > 0
    ) {
      const mergedData = JSON.parse(JSON.stringify(lastData.value))

      // 更新每一条新数据
      currentData.forEach((newItem) => {
        const index = mergedData.findIndex(
          (item) => item[options.idField] === newItem[options.idField]
        )
        if (index !== -1) {
          mergedData[index] = newItem
        }
      })

      return mergedData
    }

    return currentData
  })

  return {
    mergedData
  }
}
