<template>
  <div class="flex-space-between">
    <div
      class="g-page-container-with-header"
      v-for="power in sortedPowerData"
      :key="power.devid"
    >
      <div class="container-header flex-space-between">
        <span class="title">电源 {{ power.devid }}</span>
        <div class="g-button" @click="handleRefreshRow(power)">更新</div>
      </div>
      <div class="container-content">
        <div class="g-section-layout">
          <div class="section">
            <div
              class="g-kv-pair"
              v-for="(label, key) in section1Labels"
              :key="key"
            >
              <div class="label">{{ label }}</div>
              <div
                class="value"
                :style="
                  key === 'status'
                    ? getStatusTextStyle(getSection1Value(power, key))
                    : {}
                "
              >
                {{ getSection1Value(power, key) }}
              </div>
            </div>
          </div>
          <div class="divider"></div>
          <div class="section">
            <div
              class="g-kv-pair"
              v-for="(label, key) in section2Labels"
              :key="key"
            >
              <div class="label">{{ label }}</div>
              <div class="value">{{ getSection2Value(power, key) }}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { useDataMerge } from '@/hooks/useDataMerge'
import { useTimeFormat } from '@/hooks/useTimeFormat'
const { formatTimestamp } = useTimeFormat()

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

import { useStatus } from '@/hooks/useStatus'
const { getStatusTextStyle } = useStatus()

import { useSortData } from '@/hooks/useSortData'

const section1Labels = {
  devid: '设备ID',
  devname: '设备名称',
  devtype: '设备类型',
  devdesp: '设备描述',
  status: '状态',
  timestamp: '时间'
}

const section2Labels = {
  waistTemperature: '腰部温度',
  leftArmTemperature: '左臂温度',
  rightArmTemperature: '右臂温度',
  leftLegTemperature: '左腿温度',
  rightLegTemperature: '右腿温度',
  leftArmCurrent: '左臂电流',
  rightArmCurrent: '右臂电流',
  leftLegCurrent: '左腿电流',
  rightLegCurrent: '右腿电流',
  waistCurrent: '腰部电流',
  headCurrent: '头部电流',
  batteryType: '电池类型',
  batteryVoltage: '电池电压',
  batteryLevel: '电池电量',
  batteryCurrent: '电池电流',
  softwareVersion: '软件版本',
  runningStatus: '运行状态',
  powerStatus: '开关机状态',
  stopStatus: '急停状态',
  remoteStopStatus: '远程急停状态'
}

// 定义需要保留2位小数的字段
const decimalFields = {
  // 温度相关
  waistTemperature: true,
  leftArmTemperature: true,
  rightArmTemperature: true,
  leftLegTemperature: true,
  rightLegTemperature: true,
  // 电流相关
  leftArmCurrent: true,
  rightArmCurrent: true,
  leftLegCurrent: true,
  rightLegCurrent: true,
  waistCurrent: true,
  headCurrent: true,
  batteryCurrent: true,
  // 电压和电量
  batteryVoltage: true,
  batteryLevel: true
}

// 定义单位
const unitMap = {
  // 温度
  waistTemperature: '°C',
  leftArmTemperature: '°C',
  rightArmTemperature: '°C',
  leftLegTemperature: '°C',
  rightLegTemperature: '°C',
  // 电流
  leftArmCurrent: 'A',
  rightArmCurrent: 'A',
  leftLegCurrent: 'A',
  rightLegCurrent: 'A',
  waistCurrent: 'A',
  headCurrent: 'A',
  batteryCurrent: 'A',
  // 电压和电量
  batteryVoltage: 'V',
  batteryLevel: '%'
}

// 获取电源数据，兼容13和61命令
const powerData = useDataMerge(
  computed(() => {
    const data = received.value?.statusData?.powerDataList
    if (!data || data.length === 0) {
      return [
        {
          devdesp: '暂无'
        }
      ]
    }
    return data
  })
).mergedData

const sortedPowerData = useSortData(powerData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

const getSection1Value = (item, key) => {
  let value = item[key]
  if (key === 'timestamp' && value) {
    value = formatTimestamp(value)
  }
  return value === null || value === undefined || value === '' ? '-' : value
}

const getSection2Value = (item, key) => {
  const value = item[key]
  if (value === null || value === undefined || value === '') return '-'

  if (decimalFields[key]) {
    const formattedValue = Number(value).toFixed(2)
    return unitMap[key] ? `${formattedValue}${unitMap[key]}` : formattedValue
  }

  return value.toString()
}

// 单行刷新处理
const handleRefreshRow = (item) => {
  if (item.devid) {
    sendGetStatusData('power', item.devid)
  }
}

// 等socket连接后发送13命令获取数据
watch(
  () => isConnected.value,
  (newStatus) => {
    if (newStatus) {
      sendGetStatusData('power')
    }
  },
  { immediate: true }
)
</script>

